1	/// Compile ans.proto at build time.
2	fn main() -> Result<(), Box<dyn std::error::Error>> {
3	    // Use vendored protoc so users don't need to install it separately.
4	    std::env::set_var("PROTOC", protoc_bin_vendored::protoc_bin_path().expect("protoc not found — install protobuf compiler or enable protoc-bin-vendored"));
5	
6	    tonic_build::configure()
7	        .build_server(true)
8	        .build_client(true)
9	        .protoc_arg("--experimental_allow_proto3_optional")
10	        .compile_protos(&["../../proto/ans.proto"], &["../../proto"])?;
11	    println!("cargo:rerun-if-changed=../../proto/ans.proto");
12	    Ok(())
13	}
