1	//! Prometheus-compatible metrics for observability.
2	//!
3	//! Lightweight in-process metrics using atomics — no external
4	//! crate dependency. Exposed at `GET /api/v1/metrics` in
5	//! Prometheus text exposition format.
6	
7	use std::fmt::Write as FmtWrite;
8	use std::sync::atomic::{AtomicI64, AtomicU64, Ordering};
9	use std::time::Instant;
10	
11	/// Global metrics store, zero-alloc after init.
12	pub struct Metrics {
13	    pub sessions_active: AtomicI64,
14	    pub actions_total: AtomicU64,
15	    pub goals_active: AtomicI64,
16	    pub screenshots_total: AtomicU64,
17	    pub errors_total: AtomicU64,
18	    pub dom_requests_total: AtomicU64,
19	    pub immune_scans_total: AtomicU64,
20	    pub decisions_stored: AtomicU64,
21	    start_time: Instant,
22	}
23	
24	impl Metrics {
25	    #[must_use]
26	    pub fn new() -> Self {
27	        Self {
28	            sessions_active: AtomicI64::new(0),
29	            actions_total: AtomicU64::new(0),
30	            goals_active: AtomicI64::new(0),
31	            screenshots_total: AtomicU64::new(0),
32	            errors_total: AtomicU64::new(0),
33	            dom_requests_total: AtomicU64::new(0),
34	            immune_scans_total: AtomicU64::new(0),
35	            decisions_stored: AtomicU64::new(0),
36	            start_time: Instant::now(),
37	        }
38	    }
39	
40	    pub fn inc_sessions(&self, delta: i64) {
41	        self.sessions_active.fetch_add(delta, Ordering::Relaxed);
42	    }
43	
44	    pub fn inc_actions(&self) {
45	        self.actions_total.fetch_add(1, Ordering::Relaxed);
46	    }
47	
48	    pub fn inc_goals(&self, delta: i64) {
49	        self.goals_active.fetch_add(delta, Ordering::Relaxed);
50	    }
51	
52	    pub fn inc_screenshots(&self) {
53	        self.screenshots_total.fetch_add(1, Ordering::Relaxed);
54	    }
55	
56	    pub fn inc_errors(&self) {
57	        self.errors_total.fetch_add(1, Ordering::Relaxed);
58	    }
59	
60	    pub fn inc_dom_requests(&self) {
61	        self.dom_requests_total.fetch_add(1, Ordering::Relaxed);
62	    }
63	
64	    pub fn inc_immune_scans(&self) {
65	        self.immune_scans_total.fetch_add(1, Ordering::Relaxed);
66	    }
67	
68	    pub fn inc_decisions(&self) {
69	        self.decisions_stored.fetch_add(1, Ordering::Relaxed);
70	    }
71	
72	    #[must_use]
73	    pub fn uptime_seconds(&self) -> f64 {
74	        self.start_time.elapsed().as_secs_f64()
75	    }
76	
77	    /// Render all metrics in Prometheus text exposition format.
78	    #[must_use]
79	    pub fn render(&self) -> String {
80	        let mut buf = String::with_capacity(1024);
81	        let uptime = self.uptime_seconds();
82	
83	        gauge(&mut buf, "ans_uptime_seconds", uptime, "Daemon uptime");
84	        gauge(
85	            &mut buf,
86	            "ans_sessions_active",
87	            self.sessions_active.load(Ordering::Relaxed),
88	            "Active browser sessions",
89	        );
90	        counter(
91	            &mut buf,
92	            "ans_actions_total",
93	            self.actions_total.load(Ordering::Relaxed),
94	            "Total actions executed",
95	        );
96	        gauge(
97	            &mut buf,
98	            "ans_goals_active",
99	            self.goals_active.load(Ordering::Relaxed),
100	            "Active goals",
101	        );
102	        counter(
103	            &mut buf,
104	            "ans_screenshots_total",
105	            self.screenshots_total.load(Ordering::Relaxed),
106	            "Total screenshots captured",
107	        );
108	        counter(
109	            &mut buf,
110	            "ans_errors_total",
111	            self.errors_total.load(Ordering::Relaxed),
112	            "Total errors",
113	        );
114	        counter(
115	            &mut buf,
116	            "ans_dom_requests_total",
117	            self.dom_requests_total.load(Ordering::Relaxed),
118	            "Total DOM distillation requests",
119	        );
120	        counter(
121	            &mut buf,
122	            "ans_immune_scans_total",
123	            self.immune_scans_total.load(Ordering::Relaxed),
124	            "Total immune system scans",
125	        );
126	        counter(
127	            &mut buf,
128	            "ans_decisions_stored_total",
129	            self.decisions_stored.load(Ordering::Relaxed),
130	            "Total decision records stored",
131	        );
132	
133	        buf
134	    }
135	}
136	
137	fn gauge(buf: &mut String, name: &str, value: impl Into<f64>, help: &str) {
138	    write_metric(buf, name, "gauge", value, help);
139	}
140	
141	fn counter(buf: &mut String, name: &str, value: impl Into<f64>, help: &str) {
142	    write_metric(buf, name, "counter", value, help);
143	}
144	
145	fn write_metric(buf: &mut String, name: &str, mtype: &str, value: impl Into<f64>, help: &str) {
146	    let _ = writeln!(buf, "# HELP {name} {help}");
147	    let _ = writeln!(buf, "# TYPE {name} {mtype}");
148	    let _ = writeln!(buf, "{name} {}", value.into());
149	    let _ = buf.write_char('\n');
150	}
151	
152	impl Default for Metrics {
153	    fn default() -> Self {
154	        Self::new()
155	    }
156	}
